fun maxFlowMinCut(arr: IntArray): Int {
    val n = arr[0]; val m = arr[1]; val src = arr[2]; val sink = arr[3]
    val cap = Array(n) { IntArray(n) }
    for (i in 0 until m) cap[arr[4+3*i]][arr[5+3*i]] += arr[6+3*i]
    var maxFlow = 0
    while (true) {
        val parent = IntArray(n) { -1 }
        parent[src] = src
        val queue = ArrayDeque<Int>()
        queue.addLast(src)
        while (queue.isNotEmpty() && parent[sink] == -1) {
            val u = queue.removeFirst()
            for (v in 0 until n) if (parent[v] == -1 && cap[u][v] > 0) { parent[v] = u; queue.addLast(v) }
        }
        if (parent[sink] == -1) break
        var flow = Int.MAX_VALUE
        var v = sink
        while (v != src) { flow = minOf(flow, cap[parent[v]][v]); v = parent[v] }
        v = sink
        while (v != src) { cap[parent[v]][v] -= flow; cap[v][parent[v]] += flow; v = parent[v] }
        maxFlow += flow
    }
    return maxFlow
}

use std::collections::VecDeque;

pub fn max_flow_min_cut(arr: &[i32]) -> i32 {
    let n = arr[0] as usize;
    let m = arr[1] as usize;
    let src = arr[2] as usize;
    let sink = arr[3] as usize;
    let mut cap = vec![vec![0i32; n]; n];
    for i in 0..m { cap[arr[4+3*i] as usize][arr[5+3*i] as usize] += arr[6+3*i]; }
    let mut max_flow = 0;
    loop {
        let mut parent = vec![-1i32; n];
        parent[src] = src as i32;
        let mut q = VecDeque::new();
        q.push_back(src);
        while let Some(u) = q.pop_front() {
            if parent[sink] != -1 { break; }
            for v in 0..n {
                if parent[v] == -1 && cap[u][v] > 0 { parent[v] = u as i32; q.push_back(v); }
            }
        }
        if parent[sink] == -1 { break; }
        let mut flow = i32::MAX;
        let mut v = sink;
        while v != src { let u = parent[v] as usize; flow = flow.min(cap[u][v]); v = u; }
        v = sink;
        while v != src { let u = parent[v] as usize; cap[u][v] -= flow; cap[v][u] += flow; v = u; }
        max_flow += flow;
    }
    max_flow
}

object MaxFlowMinCut {
  def maxFlowMinCut(arr: Array[Int]): Int = {
    val n = arr(0); val m = arr(1); val src = arr(2); val sink = arr(3)
    val cap = Array.ofDim[Int](n, n)
    for (i <- 0 until m) cap(arr(4+3*i))(arr(5+3*i)) += arr(6+3*i)
    var maxFlow = 0
    var continue_ = true
    while (continue_) {
      val parent = Array.fill(n)(-1)
      parent(src) = src
      val queue = scala.collection.mutable.Queue[Int]()
      queue.enqueue(src)
      while (queue.nonEmpty && parent(sink) == -1) {
        val u = queue.dequeue()
        for (v <- 0 until n) if (parent(v) == -1 && cap(u)(v) > 0) { parent(v) = u; queue.enqueue(v) }
      }
      if (parent(sink) == -1) { continue_ = false }
      else {
        var flow = Int.MaxValue
        var v = sink
        while (v != src) { flow = math.min(flow, cap(parent(v))(v)); v = parent(v) }
        v = sink
        while (v != src) { cap(parent(v))(v) -= flow; cap(v)(parent(v)) += flow; v = parent(v) }
        maxFlow += flow
      }
    }
    maxFlow
  }
}

func maxFlowMinCut(_ arr: [Int]) -> Int {
    let n = arr[0], m = arr[1], src = arr[2], sink = arr[3]
    var cap = [[Int]](repeating: [Int](repeating: 0, count: n), count: n)
    for i in 0..<m { cap[arr[4+3*i]][arr[5+3*i]] += arr[6+3*i] }
    var maxFlow = 0
    while true {
        var parent = [Int](repeating: -1, count: n)
        parent[src] = src
        var queue = [src]
        var front = 0
        while front < queue.count && parent[sink] == -1 {
            let u = queue[front]; front += 1
            for v in 0..<n {
                if parent[v] == -1 && cap[u][v] > 0 { parent[v] = u; queue.append(v) }
            }
        }
        if parent[sink] == -1 { break }
        var flow = Int.max
        var v = sink
        while v != src { flow = min(flow, cap[parent[v]][v]); v = parent[v] }
        v = sink
        while v != src { cap[parent[v]][v] -= flow; cap[v][parent[v]] += flow; v = parent[v] }
        maxFlow += flow
    }
    return maxFlow
}

export function maxFlowMinCut(arr: number[]): number {
    const n = arr[0], m = arr[1], src = arr[2], sink = arr[3];
    const cap: number[][] = Array.from({ length: n }, () => new Array(n).fill(0));
    for (let i = 0; i < m; i++) cap[arr[4+3*i]][arr[5+3*i]] += arr[6+3*i];
    let maxFlow = 0;
    while (true) {
        const parent = new Array(n).fill(-1);
        parent[src] = src;
        const queue = [src];
        let front = 0;
        while (front < queue.length && parent[sink] === -1) {
            const u = queue[front++];
            for (let v = 0; v < n; v++)
                if (parent[v] === -1 && cap[u][v] > 0) { parent[v] = u; queue.push(v); }
        }
        if (parent[sink] === -1) break;
        let flow = Infinity;
        for (let v = sink; v !== src; v = parent[v]) flow = Math.min(flow, cap[parent[v]][v]);
        for (let v = sink; v !== src; v = parent[v]) { cap[parent[v]][v] -= flow; cap[v][parent[v]] += flow; }
        maxFlow += flow;
    }
    return maxFlow;
}
